/framework/src/Illuminate/Pipeline/Pipeline.php(116): Illuminate\\Pipeline\\Pipeline->Illuminate\\Pipeline\\{closure}()\n#30 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Routing/Router.php(799): Illuminate\\Pipeline\\Pipeline->then()\n#31 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Routing/Router.php(776): Illuminate\\Routing\\Router->runRouteWithinStack()\n#32 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Routing/Router.php(740): Illuminate\\Routing\\Router->runRoute()\n#33 /home/cutefish/Videos/Octobercms/generalogolla/vendor/october/rain/src/Router/CoreRouter.php(32): Illuminate\\Routing\\Router->dispatchToRoute()\n#34 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Foundation/Http/Kernel.php(190): October\\Rain\\Router\\CoreRouter->dispatch()\n#35 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Pipeline/Pipeline.php(141): Illuminate\\Foundation\\Http\\Kernel->Illuminate\\Foundation\\Http\\{closure}()\n#36 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Foundation/Http/Middleware/PreventRequestsDuringMaintenance.php(86): Illuminate\\Pipeline\\Pipeline->Illuminate\\Pipeline\\{closure}()\n#37 /home/cutefish/Videos/Octobercms/generalogolla/vendor/october/rain/src/Foundation/Http/Middleware/CheckForMaintenanceMode.php(23): Illuminate\\Foundation\\Http\\Middleware\\PreventRequestsDuringMaintenance->handle()\n#38 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Pipeline/Pipeline.php(180): October\\Rain\\Foundation\\Http\\Middleware\\CheckForMaintenanceMode->handle()\n#39 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Pipeline/Pipeline.php(116): Illuminate\\Pipeline\\Pipeline->Illuminate\\Pipeline\\{closure}()\n#40 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Foundation/Http/Kernel.php(165): Illuminate\\Pipeline\\Pipeline->then()\n#41 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Foundation/Http/Kernel.php(134): Illuminate\\Foundation\\Http\\Kernel->sendRequestThroughRouter()\n#42 /home/cutefish/Videos/Octobercms/generalogolla/index.php(43): Illuminate\\Foundation\\Http\\Kernel->handle()\n#43 /home/cutefish/Videos/Octobercms/generalogolla/vendor/october/rain/src/Foundation/resources/server.php(18): require_once(\'...\')\n#44 {main}\n\nNext Illuminate\\Database\\QueryException: SQLSTATE[22001]: String data, right truncated: 1406 Data too long for column \'comments\' at row 1 (SQL: insert into `briddle_data_import` (`author`, `comments`, `created_at`, `created_at_old`, `status`, `statusoriginal`, `updated_at`, `updated_at_old`) values (Apollo Aloka, We,as humans tend to talk about character without having the opportunity to come up close and personal with ardents such as General Ogolla. I have learned from the best.The General was a man of CHARACTER.He espoused integrity, commitment and honesty.Let as embrace these virtues in his honour., 2024-04-30 06:02:32, 2024-04-30T06:02:32.135Z, 1, approved, 2024-04-30 08:27:43, 2024-04-30T08:27:43.978Z), (ogeorgias, Man\'s main task in life is to give birth to himself, to become what he potentially is. The most important product of his effort is his own personality. You achieved this effortlessly and to even think of emulating your personality is a blessing. Thank you sir!, 2024-04-30 17:55:20, 2024-04-30T17:55:20.843Z, 1, approved, 2024-04-30 19:11:57, 2024-04-30T19:11:57.437Z), (Zuena Anjela, My precious Uncle!!! What a loss!!! We shall remain strong even though we feel weak. We shall smile even though we feel sad😔 Thank you for living a life worth emulating. I choose to keep the memories. May your gentle soul and sweet spirit rest in the Lord\'s bossom until we meet again on the resurrection morning. Fare the well🙏🏾, 2024-04-30 18:19:31, 2024-04-30T18:19:31.202Z, 1, approved, 2024-04-30 19:11:34, 2024-04-30T19:11:34.539Z), (Abwonji Paul, In honor of General Ogolla, we celebrate a life dedicated to service, leadership, and unwavering faith. \n\nHis commitment to his country and his people exemplified courage, integrity, and humility, reflecting the highest ideals of service to others.\n\nGeneral Ogolla\'s legacy is not only one of military prowess but also of a deep, abiding faith that guided his actions and decisions. His wisdom and power to forgive was a gift given to him by the Almighty. \n\nMay his life continue to inspire us to strive for excellence and to always give glory to God in all that we do and live a purposeful life like him.\n\nI find comfort in the fact that God allowed him to rest that God may be glorified (many lives have been changed and drowned to Christ in his rest) and the fact that God has not given us the power to know what lies ahead of us. We give God all the glory because he allowed this to happen and God has not given us power to understand.\n\nWhen i remember my brother i give God all the glory and use the lessons i learnt from him to live a purposeful life ahead of me, 2024-04-30 19:11:22, 2024-04-30T19:11:22.734Z, 1, approved, 2024-04-30 19:12:22, 2024-04-30T19:12:22.110Z), (Mokaya Enock, A God given, humble and generous leader who would appreciates everything. No words can describe his commitment, integrity, kindness and love for everyone who came across him. \n\nSir, you were a leader and dad to many. I salute you sir. May our good Lord bless your entire family., 2024-04-30 19:57:55, 2024-04-30T19:57:55.481Z, 1, approved, 2024-04-30 20:33:32, 2024-04-30T20:33:32.183Z), (Jemimahveki, Your love for God and Church its something motivated me alot,your encouragement and helping the needy learnt alot from you,may your soul rest in peace.may God comfort you mrs ogolla and your entire family., 2024-04-30 19:58:06, 2024-04-30T19:58:06.899Z, 1, approved, 2024-04-30 20:33:17, 2024-04-30T20:33:17.083Z), (Major Makori Mitunda, It was on 3rd April 1984 when I had just reported to Moi Airbase as Aircrew Cadet that I met Francis Ogolla at the main gate.\nHe was speaking very fluent English with the gate Airforce police. He was telling them to allow him in to see the Airforce Commander to ask him why he should not be allowed to join as an Aircrew cadet since he had all the qualifications. He told them that no officer cadet was taken from Luo Nyanza because of the coup de tat which was staged by Ochuka and that should not be a blanket condemnation. He was very categorical as he was fighting for his rights as a citizen of Kenya. \nFinally he was allowed in and joined us where we shown to sleep. I was with the late JC Langat and the late Itur. And Ogolla was a dreamer. He used to tell us that one day he will be the Airdorce Commander and we used to laugh at that. The Base Comnander was a Kisii by the name Colonel Atambo and we used to wonder how it happened that such a person from a small tribe can be in such a big command position having flown so many aircrafts? We later found out that Colonel Atambo grew up in Kaloleni - Nairobi and his father used to work with Kenya Railways. That is how he got the exposure to join the Airforce as an Aircrew after independence. \nThat time we joined 82 Airforce and the Lt General Mihammed.was the Airforce Commander. So when we were aptitudes, Ogolla was left out, because he had not been cleared. Us we taught he might not be allowed. He came to be cleared after one week struggle with authorities. I think GeneralMuhammud was very understanding and somehow he was allowed to join as an Aircrew. He did the aptitude and passed and also passed medical which was very tough.\nWhat I can say the Francis Ogolla was a fighter from the word go. He was very focused and never joined us whenever we went out to enjoy ourselves at Mateso Hill chuki, Bubbles and Dumbusters for one for the road. He married early and started family life early and left us enjoying.life. Ogolla showed me what it means to have dreams in life. We were at the same rank of Major togethe and we even lost hope of getting promoted because of coming from western Kenya. But ones destiny is determined by God. I retired as major in 2011 and left Ogolla as Basecommander. I have been telling my friends about Ogolla. He took us to his home in Siaya and ate at his home and we met mama and Dad at Alego Usonga. We have chatting I our group and we had planning to celebrate our 40 years on 27th April and he was to buy us Lunch and have a thanks giving. But life can be too short.\nI have all reasons to say we shall meet again in that resurrection morning when Jesus comes again.., 2024-04-30 20:15:15, 2024-04-30T20:15:15.713Z, 1, approved, 2024-04-30 20:33:01, 2024-04-30T20:33:01.500Z), (Martin Kithinji, \"I know I will take my last breath one day, but I can\'t say I\'m ready for that eventuality. The thought of leaving this world and all that is dear to me is daunting. But then I\'m reminded of the legacy of people like Gen Ogola, who lived life to the fullest and was unafraid of death. I must say that I admire what I have heard people share about him. Although he is no longer with us, I wish I could have met him and experienced the awe, maybe in the next life.\n\nIn my personal experience, I have found that contemplating the inevitability of death has helped me appreciate the present moment more fully. It has encouraged me to live my life with purpose and intention, to cherish my loved ones and pursue my passions. I believe that it is the small moments that make life worth living, and I try to make the most of each day.\n\nAlthough the idea of death can be scary, it is also a reminder to live life to the fullest. In the face of mortality, we can choose to focus on the beauty and wonder of life. I am grateful for each day and the opportunities it brings, and I hope to make the most of the time I have left.\" There is much to unravel about General Ogolla. A biography would suffice to immortalize his legacy. We will miss you, Sir!, 2024-04-30 20:15:54, 2024-04-30T20:15:54.318Z, 1, approved, 2024-04-30 20:32:35, 2024-04-30T20:32:35.749Z), (Otero Smith, Uncle was an epitome of selflessness, extending care to all without distinction. Our last encounter on that Sunday, preceding the tragic accident, was cherished; his anticipation for the week ahead was palpable, igniting excitement for the forthcoming event we were to share. Through thick and thin, he remained a steadfast pillar of support for our family. As we await the dawn of judgment day, I find solace in knowing that he is now in the company of our departed loved ones. My prayers are a continuous stream, beseeching divine healing and fortitude for our grieving family. Your memory will forever be etched in our hearts, and may your noble deeds and admirable character be reincarnated in another soul., 2024-04-30 20:47:44, 2024-04-30T20:47:44.618Z, 1, approved, 2024-05-01 05:53:19, 2024-05-01T05:53:19.617Z), (Lorna Akinyi, Esteemed Uncle Francis, \nAs I write this tribute I am filled with gratitude. You were more than an uncle to us; you have been the guiding light of our extended family ; offering wisdom, support and unwavering love. Your kindness knew no bounds . You have taught me the importance of humility, empathy and generosity. I cherish every memory we shared in family gatherings and shared laughter. \n\nThough you are no longer with us Uncle, your spirit lives on and the lessons you taught us will remain etched forever. Thank you for everything you will be deeply missed but never forgotten., 2024-04-30 23:03:53, 2024-04-30T23:03:53.984Z, 1, approved, 2024-05-01 05:53:35, 2024-05-01T05:53:35.117Z), (Presley Mostyn, What a man! A man of honour. A man of character. You exemplified true meaning of generosity, kindness, understanding, caring and above all humility. You were a voice of reason and did your best to promote peace among family members. You kept teaching us about vanity and material possessions. You had it all but you chose to be simple, what a rare kind! So so many valuable lessons and traits to be emulated. I was really looking forward to meeting you on 20th April at home. The news of your sudden demise was an utter shock! It confused me, brought pain and weakness to my whole body, i found it hard to believe and accept it. It is well. Go well uncle! We will truly miss you!, 2024-05-01 03:43:47, 2024-05-01T03:43:47.352Z, 1, approved, 2024-05-01 05:53:49, 2024-05-01T05:53:49.063Z), (Alfayo Nyaberi, His courage nerves a thousand living men, the tranquil and steady dedication of his lifetime will inspire generations to come, He had the clearest vision of what is before him, glory and danger alike, and yet notwithstanding, go out to meet it as a soldier.... He will always live in our hearts, 2024-05-01 03:50:02, 2024-05-01T03:50:02.045Z, 1, approved, 2024-05-01 05:54:06, 2024-05-01T05:54:06.679Z), (Paula Onyango, To the world he is a General but to me he is “Nera”. Hes was a light to many but a star to his family. Uncle had a solution to every problem. I remember my visits to Nairobi. When we had family gatherings Uncle would tell stories, nothing related to the military and we would laugh and laugh, then he ends with a punchline “whatever you do, do it to your best, ama kama huwezi, jaribu kitu ingine” I will miss you. And pass my love to Grandma., 2024-05-01 04:47:59, 2024-05-01T04:47:59.500Z, 1, approved, 2024-05-01 05:54:14, 2024-05-01T05:54:14.476Z), (Maina, Gen. Ogola was a downhearted person. I interacted with him in his office and he was very helpful and guided so well. He was great mentor. General also had very good plans for this country and the people. It is my prayer that the next CDF fits well in those Ogola shoes. He can only make it better, no dropping., 2024-05-01 07:25:31, 2024-05-01T07:25:31.298Z, 1, approved, 2024-05-01 18:05:40, 2024-05-01T18:05:40.743Z), (Lepore Kirorei, Sir,\n\nI’m remiss of words to express the kind of human being you were. A mentor, a father figure, a leader, our constant inspiration. An excellent human being. Our true north whenever we felt lost and adrift. You taught us the importance of service with humility and kindness . Many a times, we tested your patience and tolerance and you always responded with kindness, love and guidance.\n\nA general who accomplished so much in so short a time!\n\nDespite your busy schedule, you always taught us the important values of family, faith and generosity. And to that we will forever remain grateful!\n\nSir, it was the honour of our lives to serve you. We pray that God keeps your soul in perfect eternal peace till we meet again.\n\nRest well with the angels sir., 2024-05-01 07:48:00, 2024-05-01T07:48:00.298Z, 1, approved, 2024-05-01 18:05:33, 2024-05-01T18:05:33.979Z), (Faith Odero, Death is the last chapter in time but the first chapter in eternity.\n\nThank you for sharing your life with us and all the lessons you gave us.\n\nYour personality, countless deeds of kindness, always giving and never expecting any favours in return, selfishness, humility is worth emulating and I hope to be just half of what you were in your honour.\n\nYou will forever remain in our hearts. May your soul rest in peace Uncle., 2024-05-01 08:35:35, 2024-05-01T08:35:35.893Z, 1, approved, 2024-05-01 18:05:27, 2024-05-01T18:05:27.403Z), (Caroline Aredo, General, Baba Achi, Uncle- Let me start by quoting John 11:25 ‘I am the resurrection and the life. Anyone who believes in me will live, even after dying’.\n We have lost you here on earth and when we lose someone we love, we must live with the love they left behind. ‘Uncle’ as we fondly referred to you, we are living with the sincere love you showed. I met you in Nanyuki and you introduced me to a young innocent lady Aileen and this was the beginning of a cherished long-lasting relationship with your family. You, Aileen and the children are now more than relatives to us. I’m struggling with the past tense when referring to you. I will never forget the voice welcoming me and my children on our visits. \nTo my friend Aileen the LORD is with you., 2024-05-01 10:05:47, 2024-05-01T10:05:47.360Z, 1, approved, 2024-05-01 18:05:19, 2024-05-01T18:05:19.114Z), (, Met my boss during a visit at my place of work, had an opportunity to exchange a moment of few words , He wanted to know me and my roles, without saying much he encouraged me to continue giving the service I was entrusted with. Inside my heart I was very encouraged by this. Shine on your way my brother and friend. To the family, DO NOT BE AFRAID, says the Lord., 1899-12-30 00:00:00, , 0, pending, 1899-12-30 00:00:00, ), (Leah Okoko, I will hold on to this words he said, men are mortals. In his service he has really seen the mortality of men. This gives me the courage to live one day at a time., 2024-05-01 13:20:33, 2024-05-01T13:20:33.268Z, 1, approved, 2024-05-01 18:04:44, 2024-05-01T18:04:44.764Z), (Crispo Emmanuel Oduol, With a heavy heart I have to come to terms that you are no more. Memories of you keep on lingering in my mind. The best of it was listening to your counsel as we sip some wine. You did alot to me and I truly appreciate. You are a true soldier and the best Uncle. Your life on earth was a blessing to all. Till we meet again Uncle Francis., 2024-05-01 15:48:32, 2024-05-01T15:48:32.841Z, 1, approved, 2024-05-01 18:04:31, 2024-05-01T18:04:31.973Z), (Simon afuya, What a wonderful general this country had.\nI personally can say the entire ogola family is just a blessing...you feel it anytime you encountered them..Mama aileen ,joel and Lorna completely reflected the goodness of generali.\nWe pray For God\'s special favour to abide by this amazing family in all their endeavours 🙏\n\nRest easy generali your legacy shall never fade away from generation to generation, 2024-05-01 16:24:41, 2024-05-01T16:24:41.230Z, 1, approved, 2024-05-01 18:04:23, 2024-05-01T18:04:23.331Z), (George Rukwaru, We lost a real General, a great patriot. May your soul rest in eternal peace, 2024-05-01 17:23:10, 2024-05-01T17:23:10.451Z, 1, approved, 2024-05-01 18:04:12, 2024-05-01T18:04:12.324Z), (Kosne, Sometimes life sucks when you lose someone you value so much. RIP my commander, 2024-05-01 19:00:56, 2024-05-01T19:00:56.476Z, 1, approved, 2024-05-01 19:07:16, 2024-05-01T19:07:16.331Z), (Lt Mung\'asia, Sir, \nYou fought till the end. From your life, I have learnt a lot but too bad because you have already gone. \nI will forever seek knowledge the way you did.\nYour daily life was an inspiration to every Officer, Soldier and civilian.\nRest in Eternal Peace., 2024-05-01 19:31:02, 2024-05-01T19:31:02.952Z, 1, approved, 2024-05-01 19:47:01, 2024-05-01T19:47:01.190Z), (Kedii, You will always remain our hearts sir may your soul rest in eternal.I have alot from you as a leader and a family man,in terms of simplicity and humility.Your family is a good example of children raised with good morals and good virtues., 2024-05-01 19:34:42, 2024-05-01T19:34:42.252Z, 1, approved, 2024-05-01 19:48:09, 2024-05-01T19:48:09.778Z), (Pkay, God is the Grand Master. My heart accepts, God makes All things Beautiful in His Time. Rest well., 2024-05-01 19:35:21, 2024-05-01T19:35:21.323Z, 1, approved, 2024-05-01 19:48:11, 2024-05-01T19:48:11.052Z), (Linda Aredo, Though we are really sad about Uncle’s passing, I am thankful to have known him and for the impactful life he had here on earth. Any interaction I had with Uncle and his family made me want to be a better citizen and Christian, it created a feeling of ‘I can do it’. It is like me and my brother Brian had our very own ‘Hypeman’ I recall he once mentioned he had finished reading the book ‘Mastery’ by Robert Greene and I went to buy a copy and read it almost immediately after because I admired how studious he was.\nHis nuggets of wisdom have helped me in my career and in life. He set a great example of living Christian values through his work and family which many of us will emulate., 2024-05-01 20:09:43, 2024-05-01T20:09:43.335Z, 1, approved, 2024-05-01 20:34:18, 2024-05-01T20:34:18.226Z), (Ochibo7, May God comfort General\'s family., 2024-05-01 20:20:16, 2024-05-01T20:20:16.061Z, 0, rejected, 2024-05-02 11:36:26, 2024-05-02T11:36:26.847Z), (Ess Atera, RIP General!, 2024-05-01 21:20:21, 2024-05-01T21:20:21.459Z, 0, rejected, 2024-05-02 11:36:42, 2024-05-02T11:36:42.124Z), (Essie Nini, RIEP General, 2024-05-01 22:38:36, 2024-05-01T22:38:36.811Z, 0, rejected, 2024-05-02 11:36:55, 2024-05-02T11:36:55.606Z), (George Mbagara, Rest in peace my dear friend. You were a great man of resolute steps., 2024-05-02 01:09:01, 2024-05-02T01:09:01.479Z, 1, approved, 2024-05-02 05:36:30, 2024-05-02T05:36:30.977Z), (Varma, Rest in peace our heroe, 2024-05-02 03:13:08, 2024-05-02T03:13:08.228Z, 0, rejected, 2024-05-02 11:37:16, 2024-05-02T11:37:16.777Z), (Sarah maria, May the Lord protect your family against all dark forces .precious are those who die in the sight of God, 2024-05-02 04:23:24, 2024-05-02T04:23:24.716Z, 1, approved, 2024-05-02 05:35:56, 2024-05-02T05:35:56.673Z), (Liza Dama, You were indeed a shining embodiment of leadership and humility, qualities I aspire to embody myself. Every moment we spent together was cherished, as you consistently imparted wisdom for me to live by. May your soul find eternal peace. I believe you’re now a guiding angel, watching us from above., 2024-05-02 06:39:44, 2024-05-02T06:39:44.105Z, 1, approved, 2024-05-02 07:41:42, 2024-05-02T07:41:42.263Z), (Caroline, Only met the General once - last year during an occasion at their home. I had the honor of sitting at the same table as he and others. I was struck by his humility. He served us - a rare virtue for a man of his stature. In my conversations with him that evening, we discovered we came from the same area back in Alego, Siaya County. He was neighbors with my aunt. He struck me as open and authentic as it was easy to talk with him. He encouraged me to give my best to my children. \nMay God watch over his family and friends., 2024-05-02 06:53:05, 2024-05-02T06:53:05.055Z, 1, approved, 2024-05-02 07:41:17, 2024-05-02T07:41:17.180Z), (Gilisho, I first heard the of name Francis Ogolla when he was helping me secure a job.. \nThis kind man not from my tribe did what he could and secured me the job.. we had never met not until when he visited where I worked and I had the privilege to finally greet him.. \n\nHe was a kind man even with his words ..Rest Easy General.. \n\nPainful.., 2024-05-02 09:30:49, 2024-05-02T09:30:49.827Z, 1, approved, 2024-05-02 10:47:49, 2024-05-02T10:47:49.841Z), (Charlene Chelagat Ruto, I usually think I am hardcore and my tears are far all till you passed on and I cried so hard. It\'s funny how now when I am in situations that test my integirty and humility I ask myself \'What would General Ogolla do in this situation?\'. You were my mentor and believed in my crazy dreams for the young people. Thank you for your support while you were alive and for your wisdom even now., 2024-05-02 09:48:00, 2024-05-02T09:48:00.207Z, 1, approved, 2024-05-02 10:47:12, 2024-05-02T10:47:12.167Z), (George Odhiambo, It was with profound shock that I learnt of General\'s passing on. Even now, it is very difficult to believe that Baba Archie or Uncle Francis (as we fondly referred to General) has rested. And yet, I take comfort in the knowledge that Baba Archie was one of the most faithful and diligent Christians I have known. A dignified, humble man who valued people (basically everyone) for who they are and not what positions they hold or their social status. I thank God for the privilege to have known him and interacted with him closely and I cherish the memories. \n\nWe visited uncle Francis on several occasions but I fondly remember the time we visited him in Laikipia when he was the base commander. Every night before retiring to bed he\'d pray with us and one statement still rings in my ears: \'...Lord if you allow us to see tomorrow, may we be careful enough to give thanks\'. That was Uncle. How we often forget that we can be called home any moment and should therefore be ready. His humble demeanour, inspite of his seniority, and generosity should be a lesson to us all. \n\nI pray for God\'s comfort to Auntie Aileen, Archie, Joel, Muthoni, Taji and all other relatives. \n\n2 Corinthians 1:3-4: Blessed be the God and Father of our Lord Jesus Christ, the Father of mercies and God of all comfort, who comforts us in all our affliction, so that we may be able to comfort those who are in any affliction, with the comfort with which we ourselves are comforted by God.\n\nHis legacy lives on. \n\nYou served your country and humanity faithfully and with dedication, focus and diligence.\n\nYou fought a good fight, you finished the race, you kept the faith. \n\nRest in eternal peace Uncle Francis., 2024-05-02 10:33:46, 2024-05-02T10:33:46.190Z, 1, approved, 2024-05-02 10:46:37, 2024-05-02T10:46:37.178Z), (John Wesley Nguuh, General Ogolla stood out as a role model Christian professional who unapologetically stood as a witness for Christ in his sphere of influence. He stood out as a responsible family man and member of human society who made everyone who interacted with him as loved and loved regardless of one\'s position in society.\n\nEvery meeting with the General was memorable and full of life lessons. My first encounter with him is vividly etched in my memory as he taught me how the military are expected to relay messages. \n He had come to our house as the Chairman of the Christian Military Fellowship to invite me to speak in one of their meetings. He flatly but respectfully declined to be first served refreshments before he relayed his message. He informed my wife and I that in the military it was customary for the messenger to relay the message first before one is given any kind of welcome treatment which could influence one\'s message or delivery of the same. \n\nIt followed with delight as the General rose through the ranks in the military. Of special interest to me was that I had tried to join the Airforce as a cadet at the same time with him but did not qualify since I was declared \'color blind\'. I always felt we could have served as great colleagues in the military. \n\nMay the LORD grant the family, colleagues and friends comfort even as his legacy lives on through all of us who knew him or will get to know him posthumous. \n\nShalom, 2024-05-02 13:29:27, 2024-05-02T13:29:27.959Z, 1, approved, 2024-05-04 18:22:53, 2024-05-04T18:22:53.249Z), (Margaret onyango(mama Don), To Baba Achieng’ \nYou were a great family man , a man of honor and a keen listener. You uplifted my family through many trials . I am forever thankful for the wonderful memories. May your soul rest in peace ., 2024-05-02 18:29:13, 2024-05-02T18:29:13.385Z, 1, approved, 2024-05-04 18:22:38, 2024-05-04T18:22:38.409Z), (Phanuel, General was not just a family member, but a cornerstone in our lives,a true gentleman with a heart of gold. His life was vivid of true love and selflessness, leaving an indelible mark on those who were blessed to know him.Your death came as a great shock to me,I never knew u\'ll leave us that soon, your legacy lives on.Rest in peace bro ., 2024-05-04 15:15:08, 2024-05-04T15:15:08.307Z, 1, approved, 2024-05-04 18:21:56, 2024-05-04T18:21:56.743Z), (Hillary Okambo, General was not only a military General but one for us all, He inspired many people from his family , friends and colleagues. His falling was a pain that hit us below the belt. We never expected this it is still a shock to us. His Strength was trademark that will never be erased in our heart. May the spirit of the general live in Lorna & his brother to continue with his aspirations of good deeds. May he continue resting his., 2024-05-05 10:05:28, 2024-05-05T10:05:28.492Z, 1, approved, 2024-05-05 14:10:03, 2024-05-05T14:10:03.529Z), (Baba a Shawn and Ian, From that day have actually learn the importance of loving the family indeed I loved your message of the LOVE, 2024-05-05 10:05:56, 2024-05-05T10:05:56.129Z, 1, approved, 2024-05-05 14:10:08, 2024-05-05T14:10:08.091Z), (J, I pray that the family of the late Mzee remaim strong. The Lord is witb you🙏🏾, 2024-05-05 10:16:44, 2024-05-05T10:16:44.293Z, 0, pending, 2024-05-06 19:57:18, 2024-05-06T19:57:18.339Z), (Liston Mwabi, General served with purpose, and diligence and was full of humility, notwithstanding, he was a family man. \nThese admirable traits likely stemmed from his steadfast commitment to both the rule of law and the teachings of the Bible. As the saying goes, soldiers are promoted to power.\nMay his soul rest in power. He was an inspiration to the youthful generation that still believes in doing things right., 2024-05-06 09:28:12, 2024-05-06T09:28:12.186Z, 1, approved, 2024-05-06 09:31:23, 2024-05-06T09:31:23.928Z), (Janet Ogolla - Mabwa, In honour of General Francis Omondi Ogolla; I celebrate my brother’s life with a very heavy heart. His death shook me to the core and I am completely shattered. The pain is unbearable; who will wipe away our tears? I have asked so many unanswered questions.\n\nGeneral Ogolla lived a life of purpose, dedicated to God, Family and Service. \n\nHe accepted Christ as his Personal Saviour early in his life and was thirsty throughout his life to learn more about God and to walk in the footsteps of Our Lord Jesus Christ. He read the whole Bible at least once every year, for deeper understanding. \n\nHe loved and was committed to his nuclear family and the wider family. He was helping the widows in his home area and he always helped every person he came across, if he could.\n\nHe was always Passionate, Dedicated and Committed to everything he did. He was extremely Humble, Kind and Generous. Even as Chief of Defence Forces, he responded to all the text messages he received every night. \n\nHe served this Country with Wisdom, Integrity, and Humility; as he always said “He worked for God” and gave his all and his life, to this Country. He was truly a Servant Leader.\n\nHe rose through the ranks and was a good example, that God can raise an unknown person to the highest office, through difficult circumstances. At the time of his death, he was writing a book about his life and career, to encourage young people; to trust God, and to believe in Roman 8:24 “That all things work together for good for those who love God”. \n\nHe had planned to do a Doctorate degree in Theology during his retirement; to continue with his quest for deeper understanding of God, and to fully serve the Lord in his latter years. \n\nI am comforted that He is with the Lord. I know that God allowed his death for His Glory, and I believe that he has touched more lives in his death. \n\nOmondi, “You have fought the good fight, You have finished the race, You have kept the faith. Finally, there is laid up for You the Crown of righteousness, which the Lord, the righteous Judge, will give to You on that Day, and not to You only but also to all who have loved His appearing” 2 Timothy 4: 7-8.\n\nIn Honour of my brother, General Ogolla; I shall live a purposeful life dedicated to God, Family, and Service. You fondly referred to me as “Neti”. Au revoir Omondi, till we meet again Nyathiwa. Your Legacy Lives on.\n\nOmondi, Rest in Eternal Peace., 2024-05-06 15:24:15, 2024-05-06T15:24:15.105Z, 1, approved, 2024-05-06 16:02:34, 2024-05-06T16:02:34.659Z), (Purity Meme, General, I have come to know you after you have gone. But even then, you have inspired me to know God more, and to be a better citizen. May you rest in eternal peace., 2024-05-06 18:26:56, 2024-05-06T18:26:56.027Z, 1, approved, 2024-05-06 20:05:38, 2024-05-06T20:05:38.697Z), (Kahubi wa Mwangi, I admired how humble General Ogolla was. May he rest in eternal peace., 2024-05-06 20:09:51, 2024-05-06T20:09:51.829Z, 0, pending, 2024-05-06 20:09:51, 2024-05-06T20:09:51.829Z), (TITI, In the wake of your passing, I find myself grappling with emotions that words struggle to encapsulate. My brother, you were more than just a sibling; my confidant, my partner in mischief, and my unwavering source of support. You acted the role of a father to my children and a husband to me after we lost baba Wendy. Your presence illuminated every room I entered, and your absence now casts a shadow that seems impossible to dispel.\nYour kindness knew no bounds. Whether it was lending a listening ear or offering a helping hand, he approached every interaction with compassion and generosity. And your love, unconditional and unwavering, served as a beacon of warmth in the coldest of times. You offered pieces of advice, a peace maker, avoided confrontations at all levels and would share encouraging messages to family WhatsApp wall. Frequently, the shared messages pointed out that it is pointless to struggle with material wealth. The richness of you heart overflowed far beyond the pockets, you regarded wealth in simplicity, you cultivated relationships, not assets and prospered in purpose, not in possessions, you enriched the spirits of your siblings by focusing on spiritual and emotional wealth which brought more joy than material abundance ever could. Your generosity outshined gold, you built a legacy of love, not luxury, a legacy that counts; love and kindness are the inheritance that truly lasts.\nThe void left by your absence is vast and unfathomable. Yet, amidst the pain, there is solace in the memories we shared. From childhood adventures to shared triumphs and tribulations, each moment is a testament to the bond we forged as siblings. Though you may no longer walk beside me, your spirit lives on in every cherished memory and every whispered prayer.\nIn the midst of grief, I find myself clinging to the belief that love transcends the boundaries of life and death. Though you may have departed this world, the love we shared endures, an eternal flame that flickers within the recesses of my heart. And though I may never fully understand why you were called home so soon, and why it had to happen the way it happened, \"Rest assured, God’s divine justice shall reign.\" I take comfort in the knowledge that you are at peace with your maker watching over your family from a place where pain and sorrow hold no sway. \nTo my beloved brother, whose absence leaves an indelible mark upon my soul, I offer this testimony as a tribute to the light you brought into my life. Though you may be gone, your love will guide me through the darkest of nights, a beacon of hope in a world touched by loss. Until we meet again, may you rest in eternal peace.\nLoving Sister, 2024-05-07 07:58:04, 2024-05-07T07:58:04.213Z, 1, approved, 2024-05-07 10:11:56, 2024-05-07T10:11:56.931Z)) in /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Database/Connection.php:760\nStack trace:\n#0 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Database/Connection.php(720): Illuminate\\Database\\Connection->runQueryCallback()\n#1 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Database/Connection.php(546): Illuminate\\Database\\Connection->run()\n#2 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Database/Connection.php(498): Illuminate\\Database\\Connection->statement()\n#3 /home/cutefish/Videos/Octobercms/generalogolla/vendor/laravel/framework/src/Illuminate/Database/Query/Builder.php(3274): Illuminate\\Database\\Connection->insert()\n#4 /home/cutefish/Videos/Octobercms/generalogolla/plugins/briddle/data/controllers/Import.php(128): Illuminate\\Database\\Query\\Builder->insert()\n#5 /home/cutefish/Videos/Octobercms/generalogolla/modules/system/traits/DependencyMaker.php(29): Briddle\\Data\\Controllers\\Import->onImport()\n#6 /home/cutefish/Videos/Octoberc