INSERT INTO `system_plugin_history` VALUES (1,'Majos.Comments','script','1.0.1','create_comments_table.php','2024-05-07 05:19:29'),(2,'Majos.Comments','comment','1.0.1','First version of Comments','2024-05-07 05:19:29'),(3,'Majos.Test','comment','1.0.1','Initialize plugin','2024-05-07 05:19:29'),(4,'Raviraj.Rjgallery','script','1.0.1','create_galleries_table.php','2024-05-07 05:19:29'),(5,'Raviraj.Rjgallery','comment','1.0.1','Initial version of RjGallary.','2024-05-07 05:19:29'),(6,'Raviraj.Rjgallery','comment','1.0.2','jQuery inject option added to component options.','2024-05-07 05:19:29'),(7,'Raviraj.Rjgallery','comment','1.0.3','Minor bug fix.','2024-05-07 05:19:29'),(8,'Raviraj.Rjgallery','comment','1.0.4','Can now specify thumbnail resizer mode.','2024-05-07 05:19:29'),(9,'Raviraj.Rjgallery','comment','1.0.5','Multiple language support added.','2024-05-07 05:19:29'),(10,'Raviraj.Rjgallery','comment','1.0.6','Minor fix.','2024-05-07 05:19:29'),(11,'Raviraj.Rjgallery','comment','1.0.7','Added compatibility for latest version of OctoberCMS.','2024-05-07 05:19:29'),(12,'Raviraj.Rjgallery','comment','1.0.8','Add permissions management','2024-05-07 05:19:29'),(13,'Raviraj.Rjgallery','comment','1.0.9','Add CS locale','2024-05-07 05:19:29'),(14,'Raviraj.Rjgallery','comment','1.1.0','Fix deleting galleries','2024-05-07 05:19:29'),(15,'Raviraj.Rjgallery','comment','1.1.1','Fix config path for OctoberCMS build 324','2024-05-07 05:19:29'),(16,'Raviraj.Rjgallery','script','1.1.2','galleries_add_desc_field_table.php','2024-05-07 05:19:29'),(17,'Raviraj.Rjgallery','comment','1.1.2','Add slug and description in gallery model.','2024-05-07 05:19:29'),(18,'Raviraj.Rjgallery','script','1.1.3','create_categories_table.php','2024-05-07 05:19:29'),(19,'Raviraj.Rjgallery','comment','1.1.3','Add Category database and Category model.','2024-05-07 05:19:29'),(20,'Raviraj.Rjgallery','comment','1.2.0','Light gallery upgraded to v1.4, Several code optimizations','2024-05-07 05:19:29'),(21,'Raviraj.Rjgallery','comment','1.2.1','Hot fix asset loading','2024-05-07 05:19:29'),(22,'Raviraj.Rjgallery','comment','1.2.2','Page snippets registered','2024-05-07 05:19:29'),(30,'October.Demo','comment','1.0.1','First version of Demo','2024-05-07 08:25:45'),(31,'RainLab.Builder','comment','1.0.1','Initialize plugin.','2024-05-07 08:25:45'),(32,'RainLab.Builder','comment','1.0.2','Fixes the problem with selecting a plugin. Minor localization corrections. Configuration files in the list and form behaviors are now autocomplete.','2024-05-07 08:25:45'),(33,'RainLab.Builder','comment','1.0.3','Improved handling of the enum data type.','2024-05-07 08:25:45'),(34,'RainLab.Builder','comment','1.0.4','Added user permissions to work with the Builder.','2024-05-07 08:25:45'),(35,'RainLab.Builder','comment','1.0.5','Fixed permissions registration.','2024-05-07 08:25:45'),(36,'RainLab.Builder','comment','1.0.6','Fixed front-end record ordering in the Record List component.','2024-05-07 08:25:45'),(37,'RainLab.Builder','comment','1.0.7','Builder settings are now protected with user permissions. The database table column list is scrollable now. Minor code cleanup.','2024-05-07 08:25:45'),(38,'RainLab.Builder','comment','1.0.8','Added the Reorder Controller behavior.','2024-05-07 08:25:45'),(39,'RainLab.Builder','comment','1.0.9','Minor API and UI updates.','2024-05-07 08:25:45'),(40,'RainLab.Builder','comment','1.0.10','Minor styling update.','2024-05-07 08:25:45'),(41,'RainLab.Builder','comment','1.0.11','Fixed a bug where clicking placeholder in a repeater would open Inspector. Fixed a problem with saving forms with repeaters in tabs. Minor style fix.','2024-05-07 08:25:45'),(42,'RainLab.Builder','comment','1.0.12','Added support for the Trigger property to the Media Finder widget configuration. Names of form fields and list columns definition files can now contain underscores.','2024-05-07 08:25:45'),(43,'RainLab.Builder','comment','1.0.13','Minor styling fix on the database editor.','2024-05-07 08:25:45'),(44,'RainLab.Builder','comment','1.0.14','Added support for published_at timestamp field','2024-05-07 08:25:45'),(45,'RainLab.Builder','comment','1.0.15','Fixed a bug where saving a localization string in Inspector could cause a JavaScript error. Added support for Timestamps and Soft Deleting for new models.','2024-05-07 08:25:45'),(46,'RainLab.Builder','comment','1.0.16','Fixed a bug when saving a form with the Repeater widget in a tab could create invalid fields in the form\'s outside area. Added a check that prevents creating localization strings inside other existing strings.','2024-05-07 08:25:45'),(47,'RainLab.Builder','comment','1.0.17','Added support Trigger attribute support for RecordFinder and Repeater form widgets.','2024-05-07 08:25:45'),(48,'RainLab.Builder','comment','1.0.18','Fixes a bug where \'::class\' notations in a model class definition could prevent the model from appearing in the Builder model list. Added emptyOption property support to the dropdown form control.','2024-05-07 08:25:45'),(49,'RainLab.Builder','comment','1.0.19','Added a feature allowing to add all database columns to a list definition. Added max length validation for database table and column names.','2024-05-07 08:25:45'),(50,'RainLab.Builder','comment','1.0.20','Fixes a bug where form the builder could trigger the \"current.hasAttribute is not a function\" error.','2024-05-07 08:25:45'),(51,'RainLab.Builder','comment','1.0.21','Back-end navigation sort order updated.','2024-05-07 08:25:45'),(52,'RainLab.Builder','comment','1.0.22','Added scopeValue property to the RecordList component.','2024-05-07 08:25:45'),(53,'RainLab.Builder','comment','1.0.23','Added support for balloon-selector field type, added Brazilian Portuguese translation, fixed some bugs','2024-05-07 08:25:45'),(54,'RainLab.Builder','comment','1.0.24','Added support for tag list field type, added read only toggle for fields. Prevent plugins from using reserved PHP keywords for class names and namespaces','2024-05-07 08:25:45'),(55,'RainLab.Builder','comment','1.0.25','Allow editing of migration code in the \"Migration\" popup when saving changes in the database editor.','2024-05-07 08:25:45'),(56,'RainLab.Builder','comment','1.0.26','Allow special default values for columns and added new \"Add ID column\" button to database editor.','2024-05-07 08:25:45'),(57,'RainLab.Builder','comment','1.0.27','Added ability to use \'scope\' in a form relation field, added ability to change the sort order of versions and added additional properties for repeater widget in form builder. Added Polish translation.','2024-05-07 08:25:45'),(58,'RainLab.Builder','comment','1.0.28','Fixes support for PHP 8','2024-05-07 08:25:45'),(59,'RainLab.Builder','comment','1.0.29','Disable touch device detection','2024-05-07 08:25:45'),(60,'RainLab.Builder','comment','1.0.30','Minor styling improvements','2024-05-07 08:25:45'),(61,'RainLab.Builder','comment','1.0.31','Added support for more rich editor and file upload properties','2024-05-07 08:25:45'),(62,'RainLab.Builder','comment','1.0.32','Minor styling improvements','2024-05-07 08:25:45'),(63,'RainLab.Builder','comment','1.1.0','Adds feature for adding database fields to a form definition.','2024-05-07 08:25:45'),(64,'RainLab.Builder','comment','1.1.1','Adds DBAL timestamp column type. Adds database prefix support. Fixes various bugs.','2024-05-07 08:25:45'),(65,'RainLab.Builder','comment','1.1.2','Compatibility with October CMS v2.2','2024-05-07 08:25:45'),(66,'RainLab.Builder','comment','1.1.3','Adds comment support to database tables.','2024-05-07 08:25:45'),(67,'RainLab.Builder','comment','1.1.4','Fixes duplication bug saving backend menu permissions.','2024-05-07 08:25:45'),(68,'RainLab.Builder','comment','1.2.0','Improve support with October v3.0','2024-05-07 08:25:45'),(69,'RainLab.Builder','comment','1.2.2','Compatibility updates.','2024-05-07 08:25:45'),(70,'RainLab.Builder','comment','1.2.3','Fixes issue when removing items from permissions and menus.','2024-05-07 08:25:45'),(71,'RainLab.Builder','comment','1.2.5','Fixes validator conflict with other plugins.','2024-05-07 08:25:45'),(72,'RainLab.Builder','comment','1.2.6','Compatibility with October v3.1','2024-05-07 08:25:45'),(73,'RainLab.Builder','comment','2.0.1','Adds Tailor blueprint importer and code editor.','2024-05-07 08:25:45'),(74,'RainLab.Builder','comment','2.0.2','Fixes visual bug when tab fields overflow.','2024-05-07 08:25:45'),(75,'RainLab.Builder','comment','2.0.3','Fixes missing import in CMS components.','2024-05-07 08:25:45'),(76,'RainLab.Builder','comment','2.0.4','Fixes bad method name in controller model.','2024-05-07 08:25:45'),(77,'RainLab.Builder','comment','2.0.5','Fixes bug adding data table controls.','2024-05-07 08:25:45'),(78,'RainLab.Builder','comment','2.0.6','Fixes importing Tailor multisite globals.','2024-05-07 08:25:45');
/*!40000 ALTER TABLE `system_plugin_history` ENABLE KEYS */;
