INSERT INTO `system_settings` VALUES (1,'majos_comment_settings','{\"biography\":\"<p>On 28 April 2023, His Excellency Dr. William Ruto, President of the Republic of Kenya, and Commander-in-Chief of the Defence Forces, pursuant to Section 9 (2), (a) of the Kenya Defence Forces Act, promoted Lieutenant General Francis Omondi Ogolla to the rank of General and appointed him Chief of the Defence Forces (CDF). Subsequently General Francis Ogolla swearing in ceremony and investiture of ranks was held on Saturday 29th April 2023 at State House, Nairobi.<br><br>Prior to this appointment General Francis Omondi Ogolla was the Vice Chief of the Defence Forces. Gen Francis Omondi Ogolla joined the Kenya Defence Forces on 24 April 1984 and was commissioned as 2nd Lieutenant on 6 May 1985 and posted to Kenya Air Force. He trained as a fighter pilot with USAF and as an instructor pilot at the Kenya Air Force (KAF).<br><br>He also trained in other fields including imagery intelligence, counter terrorism and accident investigation.<br><br>Gen Francis O Ogolla is a graduate of ÉcoleMilitaire de Paris and National Defence College of Kenya. He holds Diploma both in International Studies and Military Science from Egerton University, a Bachelor of Arts in Political Science, Armed Conflict and Peace Studies (First Class Honors) and Masters of Arts in International Studies from the University of Nairobi.<br><br>He rose through ranks to become a Major General and appointed the Commander Kenya Air Force on 15 July 2018 a post he has served for three years. Previously he has held various appointments in Training, Command and Staff including Deputy Commander Kenya Air Force, Base Commander Laikipia Air Base, Commanding Officer of Tactical Fighter Wing, Chief Flying Instructor at Kenya Air Force Flying Training School and Operations Desk Officer at Kenya Air Force Headquarters.<br><br>He also served in the former Yugoslavia as an Observer and Military Information Officer from 1992 to 1993, as chairman of Military Christian Fellowship from 1994 to 2004 and co-Chair of Association of African Air Chiefs between 2018-2019.<br><br>Due to his dedication to service the late General Francis Omondi Ogolla was awarded several medals among them: Elder of the Golden Heart, Elder of the Burning Spear and Head of State Commendation. Recently he was also appointed as the Chairperson on the development of Kenya home of human origins museum and science park in the Lake Turkana Basin steering committee<br><br>General Francis Omondi Ogolla leaves behind a widow, Mrs. Aileen Kathambi Ogolla and two children; Lorna Achieng’ Omondi and Joel Rabuku Omondi Ogolla. He also leaves behind one daughter-in-law; Muthoni Njenga Mwaura and a grandson by the name Taji Mbagara.<\\/p>\",\"profilepic\":\"\\/Titlee.webp\"}',NULL,NULL),(2,'system_log_settings','{\"log_events\":\"1\",\"log_requests\":\"1\",\"log_theme\":\"1\"}',NULL,NULL),(3,'backend_brand_settings','{\"app_name\":\"General Ogolla\",\"app_tagline\":\"Administration Panel\",\"login_prompt\":\"Welcome back! Please login to your account to continue.\",\"color_mode\":\"light\",\"menu_mode\":\"text\",\"login_background_type\":\"color\",\"login_background_color\":\"#34495e\",\"login_background_wallpaper_size\":\"auto\",\"login_image_type\":\"autumn_images\",\"color_palette\":{\"preset\":\"default\",\"light\":{\"primary\":\"#6a6cf7\",\"secondary\":\"#72809d\",\"selection\":\"#6bc48d\",\"link_color\":\"#3498db\",\"mainnav_color\":\"#ffffff\",\"mainnav_bg\":\"#2d3134\",\"sidebar_color\":\"#536061\",\"sidebar_bg\":\"#e9edf3\",\"sidebar_active_color\":\"#333333\",\"sidebar_active_bg\":\"#ffffff\",\"sidebar_hover_bg\":\"#ffffff\",\"settings_color\":\"#536061\",\"settings_bg\":\"#f0f4f8\",\"settings_item\":\"#ffffff\",\"settings_active_color\":\"#ffffff\",\"settings_active_bg\":\"#6bc48d\",\"settings_hover_bg\":\"#dfe7ee\"},\"dark\":{\"link_color\":\"#a6a7fa\",\"sidebar_color\":\"#d7e1eA\",\"sidebar_bg\":\"#292a2d\",\"sidebar_active_color\":\"#ffffff\",\"sidebar_active_bg\":\"#424242\",\"sidebar_hover_bg\":\"#424242\",\"settings_color\":\"#adb5bd\",\"settings_bg\":\"#1b1f22\",\"settings_item\":\"#212529\",\"settings_active_color\":\"#ffffff\",\"settings_active_bg\":\"#2b3442\",\"settings_hover_bg\":\"#2b3442\",\"primary\":\"#6a6cf7\",\"secondary\":\"#72809d\",\"selection\":\"#6bc48d\",\"mainnav_color\":\"#ffffff\",\"mainnav_bg\":\"#2d3134\"}},\"show_light_switch\":\"1\",\"custom_css\":\"\"}',NULL,NULL);
/*!40000 ALTER TABLE `system_settings` ENABLE KEYS */;
